<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        load_skill_from_dir(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">SKILLS_DIR</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> /</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;doc-pipeline&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">),     </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Pattern 5: Pipeline</span></span>
